import{j as e,L as i}from"./index-ixzp0WJG.js";/* empty css               */const n=()=>e.jsxs("div",{children:[e.jsx(i,{to:"/levels",className:"backButton level-theme-love",children:"Back"}),e.jsxs("div",{className:"aLevelContainer level-theme-love",children:[e.jsx("h1",{children:"Love"}),e.jsx("p",{children:"Characterised by the development of an energy field that is progressively unconditional, unchanging, and permanent. It does not fluctuate because its source is within the person who loves and is not dependent on external factors."}),e.jsx("p",{children:"Lovingness is a way of being in and relating to the world. It is forgiving, nurturing, and supportive."}),e.jsx("p",{children:"Love is not intellectual and does not proceed from the mind. Love emanates from the heart. It has the capacity to lift others and accomplish great feats because of its purity of motive."}),e.jsx("p",{children:"As reason is bypassed, there arises the capacity for instantaneous recognition of the totality of a problem and a major expansion of context. Reason deals with particulars, whereas love deals with wholes."}),e.jsx("p",{children:"Love takes no position and thus is global, rising above the separation of positionality. It is then possible to be “one with another,” as there are no longer any barriers."}),e.jsx("p",{children:"Love dissolves negativity by recontextualising it rather than by attacking it. As such, it is benign, supportive, and nurtures life. It is the level of true happiness."}),e.jsx("p",{children:"In terms of the evolution of consciousness, this level reflects transcendence of identification with the limiting linear domain and its positionalities, and the awareness of subjectivity as the primary state that underlies all experience."}),e.jsx("p",{children:"The energy field of life is innately gratifying in and of its own quality."}),e.jsx("p",{children:"Love is available everywhere, and although it may start as conditional, with time and intention, it becomes a way of life and a way of relating to life in all its expressions."}),e.jsx("p",{children:"As love progresses, it seeks no return or gain, for it is self-rewarding by virtue of its completeness, since it has no needs."}),e.jsx("p",{children:"The capacity for love grows, so that the more one loves, the more one can love—there is no end point or limitation."}),e.jsx("p",{children:"To be loving is also to be lovable, because the world is the reflection."}),e.jsx("p",{children:"At the lower levels of consciousness, what is perceived as love is conditional and identified with possession, passion, romance, and desire, which are projected onto people or objects to give them an exciting specialness and glamour that tend to fade after the prized object or relationship is obtained. Infatuations tend to be frantic, with a fear of loss that leads to despair."}),e.jsx("p",{children:"The limitations of love have to do with perceived qualities and differences. By inner self-honesty and examination, these areas of limitation are revealed—usually as residual judgments or as the impact from prior experience."})]})]});export{n as default};
